import (
	"log"
	"strings"

	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
)

func slugify(title string) string {
	// Simple slugify for the sake of the example
	// In a real app you might use a more robust slugify library
	return strings.ReplaceAll(strings.ToLower(title), " ", "-")
}

func main() {
	app := pocketbase.New()

	app.OnRecordCreateRequest("posts").BindFunc(func(e *core.RecordRequestEvent) error {
		title := e.Record.GetString("title")
		if title == "" {
			return e.BadRequestError("Title cannot be empty", nil)
		}

		// The prompt asked to use core.Slugify(title), but it doesn't exist in PocketBase v0.31.0.
		// Using a custom slugify function instead.
		e.Record.Set("slug", slugify(title))

		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

